{
	"params": {
		"1": {
			"label": "Start date",
			"description": "Start date, e.g. \"1935\", \"c. 1205\", \"37 BCE\", \"August 1434\", \"January 1, 2017\". If a blank first date is given, a \"?\" will be generated for it.",
			"example": "1935"
		},
		"2": {
			"label": "End date",
			"description": "End date, e.g. \"present\", or any of the sorts of dates used in Start date. Use \"present\" for ongoing timespace, do not leave it blank per MOS:DATERANGE.",
			"example": "present"
		},
		"3": {
			"label": "Start date of second range",
			"description": "Start date of second range. The template only supports two date ranges. Does not work in the absence of End date having a value."
		},
		"4": {
			"label": "End date of second range",
			"description": "End date of second range. The template only supports two date ranges. Does not work in the absence of End date having a value."
		},
		"sortable": {
			"label": "Sortable",
			"description": "Only for use in sortable tables. Uses the value of |sort_date= as a sort key – or, if that was not specified, the value of one of the following, in descending order of precedence: |single=, |pre-date=, |1=, |2=, |post-date=; at least one such date must be specified for this to work.",
			"example": "yes",
			"suggestedvalues": [
				"yes"
			]
		},
		"sort_date": {
			"aliases": [
				"sortdate",
				"sort-date"
			],
			"label": "Sort date",
			"description": "Provide a custom date to sort by, e.g. ISO yyyy-mm-dd format, or \"-43\" for \"43 BCE\", or \"983\" for \"c. 983\".",
			"example": "2020-01-27"
		},
		"pre-date": {
			"aliases": [
				"pre_date",
				"predate",
				"single"
			],
			"label": "Single date before date range",
			"description": "A single date to appear before the date range (a comma-space will be inserted between them). This parameter can be \"cheated\" to show multiple dates in series, e.g. |pre-date=1645, 1652. Use Single date (post-date) and Single date before date range (pre-date) to specify independent years rather than a range, for two short, non-contiguous terms in office: {{reign|pre-date=1732|post-date=1735}} → r. 1732, 1735"
		},
		"postdate": {
			"aliases": [
				"post_date",
				"post-date"
			],
			"label": "Single date",
			"description": "A single date (typically a year) for a short reign, where no range is needed. Avoids the redundant \"r. 1872–1872\" and emits \"r. 1872\". Use Single date (post-date) and Single date before date range (pre-date) to specify independent years rather than a range, for two short, non-contiguous terms in office: {{reign|pre-date=1732|post-date=1735}} → r. 1732, 1735",
			"example": "1872"
		},
		"label": {
			"label": "Label",
			"description": "Free-form parameter for replacing \"r. \" with some other word or phrase. Overrides any |show= or |cap= values.",
			"example": "in office"
		},
		"wrap": {
			"label": "Wrap",
			"description": "Permits the content to line-wrap at key points (right after a comma, i.e. between two date ranges, between |pre-date= and |1=, between the late range date and |post-date=). Any value supplied to |wrap= will turn this option on. Does not permit wrapping within a date range, or between the \"r. \" (or replacement wording provided by |show= options) and the first date, or between the last date and |era=.",
			"example": "yes"
		},
		"show": {
			"aliases": [
				"link",
				"lk"
			],
			"label": "Show link/tooltip",
			"description": "|show=none – Produces no tooltip or link: \"r. \"; intended for use at second and later occurrences. |show=link – Replaces the <abbr> markup with a link to the Reign article: \"r. \"; rarely needed, per MOS:OVERLINKING. |show=word – Uses the word \"reigned\" instead of \"r.\": reigned  |show=colon – Uses the word \"reign\", followed by a colon, instead of \"r.\": reign:  |show=lword – Same as |show=word, but with a link to Reign article: reigned  |show=lcolon – Same as |show=colon, but with a link to Reign article: reign:  |show=blank – Shows nothing but the date values and dash, for use in tables and infoboxes with a header that already says this data indicates the reign.",
			"suggestedvalues": [
